#!/usr/bin/env bash
set -e
HOME_DIR="$HOME/promptdeed"

echo ""
echo "Installing Promptdeed TUI agent to $HOME_DIR..."
mkdir -p "$HOME_DIR/memory" "$HOME_DIR/sessions" "$HOME_DIR/bin"

base64 -d > "$HOME_DIR/bin/promptdeed" <<'PYBLOB'

PYBLOB
chmod +x "$HOME_DIR/bin/promptdeed"

mkdir -p "$HOME/.local/bin"
ln -sf "$HOME_DIR/bin/promptdeed" "$HOME/.local/bin/promptdeed"

if ! echo "$PATH" | grep -q "$HOME/.local/bin"; then
  for rc in "$HOME/.bashrc" "$HOME/.zshrc"; do
    [ -f "$rc" ] && (grep -q "$HOME/.local/bin" "$rc" || echo '''export PATH="$HOME/.local/bin:$PATH"''' >> "$rc")
  done
  export PATH="$HOME/.local/bin:$PATH"
fi

# Install xterm so the agent has its own window
if ! command -v xterm >/dev/null 2>&1; then
  echo "Installing xterm (gives the robot its own desktop window)..."
  sudo apt-get update -qq 2>/dev/null && sudo apt-get install -y xterm 2>/dev/null || echo "[xterm install skipped — agent still works in current terminal]"
fi

# Launcher: opens promptdeed in a separate xterm X11 window
cat > "$HOME_DIR/bin/promptdeed-window" <<LAUNCHER
#!/usr/bin/env bash
if command -v xterm >/dev/null 2>&1; then
  xterm -title "Promptdeed Robot" -bg "#0E1525" -fg "#E8E6E1" -fa Monospace -fs 12 -geometry 100x32 -e "bash -lc 'promptdeed; echo; read -p \"Press Enter to close...\"'"
else
  exec "$HOME_DIR/bin/promptdeed"
fi
LAUNCHER
chmod +x "$HOME_DIR/bin/promptdeed-window"
ln -sf "$HOME_DIR/bin/promptdeed-window" "$HOME/.local/bin/promptdeed-window"

# Detect Google Drive
DRIVE=""
for p in /mnt/chromeos/GoogleDrive/MyDrive "$HOME/GoogleDrive" "$HOME/Google Drive"; do
  if [ -d "$p" ]; then DRIVE="$p"; break; fi
done
if [ -n "$DRIVE" ]; then
  mkdir -p "$DRIVE/Promptdeed/memory" "$DRIVE/Promptdeed/sessions"
  echo ""
  echo "  Google Drive detected: $DRIVE"
  echo "  All AI conversations save to: $DRIVE/Promptdeed/"
fi

# ChromeOS launcher entry — opens in xterm separate window
mkdir -p "$HOME/.local/share/applications"
cat > "$HOME/.local/share/applications/promptdeed.desktop" <<DESKTOP
[Desktop Entry]
Name=Promptdeed
Comment=Private AI agent — own window
Exec=$HOME_DIR/bin/promptdeed-window
Terminal=false
Type=Application
StartupNotify=true
Categories=Utility;Development;
DESKTOP
update-desktop-database "$HOME/.local/share/applications" 2>/dev/null || true

# Pull model
if command -v ollama >/dev/null 2>&1; then
  echo ""
  echo "Pulling llama3.1 (one-time, ~4.7GB)..."
  ollama pull llama3.1 2>&1 | tail -3 || echo "[pull manually later: ollama pull llama3.1]"
fi

echo ""
echo "================================================"
echo "  Installed."
echo ""
echo "  TO OPEN THE ROBOT IN ITS OWN WINDOW:"
echo "   1. Hit the Search key on your keyboard"
echo "   2. Type: Promptdeed"
echo "   3. Click the icon"
echo ""
echo "  A separate window opens with the robot."
echo "  Your Penguin terminal stays as-is."
echo "================================================"
echo ""
